#!/usr/bin/env python3
from plugins.common.plugin_entry import nv_enrich_plugin
#By Magm
@nv_enrich_plugin("count_classes", result_scope="frame")
def process_job(job: dict) -> dict:
    """
    Cuenta cuántas detecciones hay por clase en un frame.
    """
    frame = job.get("frame")
    detections = job.get("detections", [])

    if not frame:
        return {}

    counts = {}
    for det in detections:
        cls = det.get("class_name", "unknown")
        counts[cls] = counts.get(cls, 0) + 1

    return {
        "descriptors": counts
    }
